Fix this Solid component. The displayed full name becomes stale when the parent replaces the user prop, and every mount leaks another keydown listener. Return a corrected UserCard.tsx and a focused UserCard.test.tsx. Do not change the public props type.

```tsx
import { createEffect, createSignal, onMount } from "solid-js";

type User = { first: string; last: string };

export function UserCard({ user }: { user: User }) {
  const [fullName, setFullName] = createSignal("");

  createEffect(() => setFullName(`${user.first} ${user.last}`));

  onMount(() => {
    window.addEventListener("keydown", event => {
      if (event.key === "Escape") console.log(`close ${fullName()}`);
    });
  });

  return <h2>{fullName()}</h2>;
}
```
